368	      }
369	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
370	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
371	        event.preventDefault();
372	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
373	        return;
374	      }
375	      // Close active tab — Ctrl/⌘+W.
