383	      const hotkeyLabel = event.shiftKey ? `Shift+${upper}` : upper;
384	      const tool = (Object.values(TOOL_REGISTRY) as { id: ToolId; hotkey: string }[]).find(
385	        (t) => t.hotkey === hotkeyLabel,
386	      );
387	      if (tool) {
