523	    // View sources (plan views + viewpoints + section cuts)
524	    for (const el of Object.values(elementsById) as Element[]) {
525	      if (el.kind === 'plan_view') {
526	        items.push({ id: el.id, kind: 'view', label: `Plan: ${el.name}`, keywords: 'plan view' });
527	      } else if (el.kind === 'viewpoint') {
528	        items.push({
529	          id: el.id,
530	          kind: 'view',
531	          label: `3D: ${el.name}`,
532	          keywords: 'viewpoint orbit',
533	        });
534	      } else if (el.kind === 'section_cut') {
535	        items.push({
536	          id: el.id,
537	          kind: 'view',
538	          label: `Section: ${el.name}`,
539	          keywords: 'section cut',
540	        });
541	      }
542	    }
543	    // Element sources (walls / doors / windows / rooms — top-N keep light)
544	    let elemCount = 0;
545	    for (const el of Object.values(elementsById) as Element[]) {
546	      if (el.kind !== 'wall' && el.kind !== 'door' && el.kind !== 'window' && el.kind !== 'room')
547	        continue;
548	      if (elemCount > 60) break;
549	      items.push({
550	        id: el.id,
551	        kind: 'element',
552	        label: `${el.kind}: ${(el as { name?: string }).name ?? el.id}`,
553	        keywords: el.kind,
554	      });
555	      elemCount++;
556	    }
557	    // Settings
558	    items.push(
559	      { id: 'settings.theme.light', kind: 'setting', label: 'Theme: light', keywords: 'light' },
560	      { id: 'settings.theme.dark', kind: 'setting', label: 'Theme: dark', keywords: 'dark' },
561	    );
562	    // Agent
563	    items.push({ id: 'agent.review', kind: 'agent', label: 'Run Agent Review' });
564	    return items;
565	  }, [elementsById]);
566	
567	  const handlePalettePick = useCallback(
568	    (cand: CommandCandidate) => {
569	      setRecentCommandIds((prev) => [cand.id, ...prev.filter((id) => id !== cand.id)].slice(0, 5));
570	      if (cand.kind === 'tool') {
571	        const toolId = cand.id.replace(/^tool\./, '') as ToolId;
572	        const legacy = toolIdToLegacy(toolId);
573	        if (legacy) setPlanTool(legacy);
574	        return;
575	      }
576	      if (cand.kind === 'element') {
577	        select(cand.id);
578	        return;
579	      }
580	      if (cand.id === 'settings.theme.light' || cand.id === 'settings.theme.dark') {
581	        const next = cand.id.endsWith('dark') ? 'dark' : 'light';
582	        if (getCurrentTheme() !== next) {
583	          toggleTheme();
584	          setTheme(next as Theme);
585	        }
586	        return;
587	      }
588	      if (cand.kind === 'view') {
589	        select(cand.id);
590	      }
591	    },
592	    [select, setPlanTool],
593	  );
594	
595	  /* ── Empty-state per §25 ──────────────────────────────────────────── */
596	  const emptyHint = patternFor('canvas-empty');
597	  const showEmptyState =
598	    (Object.values(elementsById) as Element[]).filter((e) => e.kind === 'wall').length === 0;
599	
600	  /* ── Compose AppShell slots ───────────────────────────────────────── */
601	  return (
602	    <>
603	      <CheatsheetModal open={cheatsheetOpen} onClose={() => setCheatsheetOpen(false)} />
604	      <RedesignedCommandPalette
