639	              <a
640	                href="/legacy"
641	                className="ml-2 mr-3 whitespace-nowrap rounded-md px-2 py-1 text-xs text-muted hover:bg-surface-strong"
642	                data-testid="legacy-route-link"
643	                title="Open the v1 panel-stack view"
