1	import { type CSSProperties, type JSX, type KeyboardEvent } from 'react';
2	import { Icons, ICON_SIZE } from '@bim-ai/ui';
3	import {
4	  alignmentForPick,
5	  compassLabelFromAzimuth,
6	  type ViewCubeAlignment,
7	  type ViewCubeCorner,
8	  type ViewCubeFace,
9	  type ViewCubePick,
10	} from './viewCubeAlignment';
11	
12	/**
13	 * ViewCube widget — spec §15.4.
14	 *
15	 * 96 × 96 px CSS-3D cube sitting top-right of the 3D canvas. Faces +
16	 * top corners are pickable. The cube rotates to mirror the live
17	 * camera's azimuth (passed in via `currentAzimuth`) so the viewer
18	 * always sees the cube oriented like the scene below.
19	 *
20	 * This implementation uses CSS `transform-style: preserve-3d` rather
21	 * than a second Three.js renderer — it ships in ~1.5 kB instead of
22	 * the ~120 kB cost of bringing up a tiny WebGL context for a 96 px
23	 * widget.
24	 */
25	
26	export interface ViewCubeProps {
27	  currentAzimuth: number;
28	  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
29	  onHome?: () => void;
30	  /** Optional className for positioning. */
31	  className?: string;
32	}
33	
34	const CUBE_SIZE_PX = 80;
35	const HALF = CUBE_SIZE_PX / 2;
36	const TILT_DEG = 25; // looking slightly down at the cube
37	// Corner picks (top of cube). Bottom corners are not exposed in the
38	// chrome — viewers don't typically want to look up at scenes.
39	const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
40	  { id: 'TOP-NW', left: '6%', top: '6%' },
41	  { id: 'TOP-NE', left: '94%', top: '6%' },
42	  { id: 'TOP-SW', left: '6%', top: '94%' },
43	  { id: 'TOP-SE', left: '94%', top: '94%' },
44	];
45	
46	interface FaceDef {
47	  id: ViewCubeFace;
48	  label: string;
49	  /** Transform that places the face on the cube. */
50	  transform: string;
51	}
52	
53	const FACES: FaceDef[] = [
54	  { id: 'FRONT', label: 'FRONT', transform: `rotateY(0deg) translateZ(${HALF}px)` },
55	  { id: 'BACK', label: 'BACK', transform: `rotateY(180deg) translateZ(${HALF}px)` },
56	  { id: 'RIGHT', label: 'RIGHT', transform: `rotateY(90deg) translateZ(${HALF}px)` },
57	  { id: 'LEFT', label: 'LEFT', transform: `rotateY(-90deg) translateZ(${HALF}px)` },
58	  { id: 'TOP', label: 'TOP', transform: `rotateX(90deg) translateZ(${HALF}px)` },
