1	/**
2	 * Camera rig for the 3D viewport — spec §15.3.
3	 *
4	 * Pure (testable) spherical-coordinate rig that supports the documented
5	 * grammar:
6	 *
7	 *   - Orbit:  `Alt + LMB drag` or middle-mouse drag.
8	 *   - Pan:    `Shift + middle-mouse drag` (or two-finger trackpad).
9	 *   - Dolly:  mouse wheel anchored at cursor; pinch.
10	 *   - Free zoom: `⌘=` / `⌘-` (delegated to `dollyBy(±k)`).
11	 *   - Frame all (`F`) and Reset (`Home`/`H`) via `frame(box)` /
12	 *     `reset(home)`.
13	 *
14	 * The rig holds: target (Vec3), radius, azimuth (theta), elevation (phi),
15	 * and an up-vector. `compose()` returns the composed camera position.
16	 *
17	 * This module is deliberately framework-free so it can be unit-tested
18	 * without a renderer; Viewport.tsx wires it to a `THREE.PerspectiveCamera`.
19	 */
20	
21	export type Vec3 = { x: number; y: number; z: number };
22	
23	export interface CameraRigSnapshot {
24	  target: Vec3;
25	  position: Vec3;
26	  up: Vec3;
27	  azimuth: number;
28	  elevation: number;
29	  radius: number;
30	}
31	
32	export interface CameraRigState {
33	  target: Vec3;
34	  up: Vec3;
35	  azimuth: number;
36	  elevation: number;
37	  radius: number;
38	  /** Bounds for `radius` (m). */
39	  minRadius: number;
40	  maxRadius: number;
41	  /** Bounds for `elevation` (radians). Spec uses [0.12, π/2 - 0.08]. */
42	  minElevation: number;
43	  maxElevation: number;
44	}
45	
46	const DEFAULT_HOME: CameraRigState = {
47	  target: { x: 0, y: 1.35, z: 0 },
48	  up: { x: 0, y: 1, z: 0 },
49	  azimuth: Math.PI / 4,
50	  elevation: 0.45,
51	  radius: 16,
52	  minRadius: 1,
53	  maxRadius: 120,
54	  minElevation: 0.12,
55	  maxElevation: Math.PI / 2 - 0.08,
56	};
57	
58	function clamp(value: number, min: number, max: number): number {
59	  return Math.max(min, Math.min(max, value));
60	}
61	
62	function add(a: Vec3, b: Vec3): Vec3 {
63	  return { x: a.x + b.x, y: a.y + b.y, z: a.z + b.z };
64	}
65	
66	function sub(a: Vec3, b: Vec3): Vec3 {
67	  return { x: a.x - b.x, y: a.y - b.y, z: a.z - b.z };
68	}
69	
70	function scale(v: Vec3, k: number): Vec3 {
71	  return { x: v.x * k, y: v.y * k, z: v.z * k };
72	}
73	
74	function length(v: Vec3): number {
75	  return Math.hypot(v.x, v.y, v.z);
76	}
77	
78	function normalize(v: Vec3): Vec3 {
79	  const l = length(v);
80	  return l === 0 ? { ...v } : scale(v, 1 / l);
81	}
82	
83	function cross(a: Vec3, b: Vec3): Vec3 {
84	  return {
85	    x: a.y * b.z - a.z * b.y,
86	    y: a.z * b.x - a.x * b.z,
87	    z: a.x * b.y - a.y * b.x,
88	  };
89	}
90	
91	function composePosition(state: CameraRigState): Vec3 {
92	  const { target, radius, azimuth, elevation } = state;
93	  return {
94	    x: target.x + radius * Math.cos(elevation) * Math.sin(azimuth),
95	    y: target.y + radius * Math.sin(elevation),
96	    z: target.z + radius * Math.cos(elevation) * Math.cos(azimuth),
97	  };
98	}
99	
100	export function createCameraRig(initial?: Partial<CameraRigState>): CameraRig {
101	  const state: CameraRigState = {
102	    ...DEFAULT_HOME,
103	    ...initial,
104	    target: { ...(initial?.target ?? DEFAULT_HOME.target) },
105	    up: { ...(initial?.up ?? DEFAULT_HOME.up) },
106	  };
107	  return new CameraRig(state, { ...DEFAULT_HOME, ...initial });
108	}
109	
110	export class CameraRig {
111	  private state: CameraRigState;
112	  private home: CameraRigState;
113	
114	  constructor(state: CameraRigState, home: CameraRigState) {
115	    this.state = state;
116	    this.home = home;
117	  }
118	
119	  /** Current immutable snapshot, including derived `position`. */
120	  snapshot(): CameraRigSnapshot {
121	    return {
122	      target: { ...this.state.target },
123	      position: composePosition(this.state),
124	      up: { ...this.state.up },
125	      azimuth: this.state.azimuth,
126	      elevation: this.state.elevation,
127	      radius: this.state.radius,
128	    };
129	  }
130	
131	  /** Orbit the camera around the target. `dxPx` and `dyPx` are unscaled
132	   * pointer deltas; the rig applies a pixel→radian factor. */
133	  orbit(dxPx: number, dyPx: number, sensitivity = 0.006): void {
134	    this.state.azimuth += dxPx * sensitivity;
135	    this.state.elevation = clamp(
136	      this.state.elevation - dyPx * sensitivity,
137	      this.state.minElevation,
138	      this.state.maxElevation,
139	    );
140	  }
141	
142	  /** Pan the rig (target + camera move together along screen-space basis). */
143	  pan(dxPx: number, dyPx: number, sensitivity = 0.005): void {
144	    const position = composePosition(this.state);
145	    const view = normalize(sub(this.state.target, position));
146	    const right = normalize(cross(view, this.state.up));
147	    const upInPlane = normalize(cross(right, view));
148	    const distance = this.state.radius * sensitivity;
149	    const delta = add(scale(right, -dxPx * distance), scale(upInPlane, dyPx * distance));
150	    this.state.target = add(this.state.target, delta);
151	  }
152	
153	  /** Dolly (zoom along the view direction). Positive `delta` moves away. */
154	  dolly(delta: number, sensitivity = 0.012): void {
155	    this.state.radius = clamp(
156	      this.state.radius + delta * sensitivity,
157	      this.state.minRadius,
158	      this.state.maxRadius,
159	    );
160	  }
161	
162	  /** Free zoom by a discrete factor (`⌘=` / `⌘-`). `factor < 1` zooms in. */
163	  zoomBy(factor: number): void {
164	    this.state.radius = clamp(
165	      this.state.radius * factor,
166	      this.state.minRadius,
167	      this.state.maxRadius,
168	    );
169	  }
170	
171	  /** Replace the target and recompute radius from the supplied position. */
172	  applyViewpoint(position: Vec3, target: Vec3, up: Vec3): void {
173	    this.state.target = { ...target };
174	    const safeUp = length(up) === 0 ? this.state.up : normalize(up);
175	    this.state.up = safeUp;
176	    const offset = sub(position, target);
177	    this.state.radius = Math.max(this.state.minRadius, length(offset));
178	    this.state.elevation = clamp(
179	      Math.asin(offset.y / this.state.radius),
180	      this.state.minElevation,
181	      this.state.maxElevation,
182	    );
183	    this.state.azimuth = Math.atan2(offset.x, offset.z);
184	  }
185	
186	  /** Frame an axis-aligned bounding box (`fitFactor` * span / 2 puts the
187	   * camera back so the box just fits in view). */
188	  frame(box: { min: Vec3; max: Vec3 }, fitFactor = 1.4): void {
189	    const cx = (box.min.x + box.max.x) / 2;
190	    const cy = (box.min.y + box.max.y) / 2;
191	    const cz = (box.min.z + box.max.z) / 2;
192	    const spanX = Math.max(box.max.x - box.min.x, 1);
193	    const spanY = Math.max(box.max.y - box.min.y, 1);
194	    const spanZ = Math.max(box.max.z - box.min.z, 1);
195	    const span = Math.max(spanX, spanY, spanZ);
196	    this.state.target = { x: cx, y: cy, z: cz };
197	    this.state.radius = clamp(span * fitFactor, this.state.minRadius, this.state.maxRadius);
198	  }
199	
200	  /** Snap to the saved home view. */
201	  reset(): void {
202	    this.state = {
203	      ...this.home,
204	      target: { ...this.home.target },
205	      up: { ...this.home.up },
206	    };
207	  }
208	
209	  /** Persist the current state as the rig's home view (for `H`). */
210	  setHome(): void {
211	    this.home = {
212	      ...this.state,
213	      target: { ...this.state.target },
214	      up: { ...this.state.up },
215	    };
216	  }
217	}
218	
219	/* ────────────────────────────────────────────────────────────────────── */
220	/* Pointer grammar — spec §15.3                                            */
221	/* ────────────────────────────────────────────────────────────────────── */
222	
223	export type PointerIntent = 'orbit' | 'pan' | 'idle';
224	
225	export interface PointerEventLike {
226	  button: number;
227	  buttons?: number;
228	  altKey?: boolean;
229	  shiftKey?: boolean;
230	  metaKey?: boolean;
231	  ctrlKey?: boolean;
232	}
233	
234	/** Map a pointer event to the documented intent.
235	 *
236	 *   - Alt + LMB      → orbit
237	 *   - Middle button  → orbit (no modifier) / pan with Shift
238	 *   - Shift + MMB    → pan
239	 *   - Two-finger trackpad scroll arrives as wheel (handled separately)
240	 */
241	export function classifyPointer(event: PointerEventLike): PointerIntent {
242	  const isLmb = event.button === 0;
243	  const isMmb = event.button === 1;
244	  if (isMmb && event.shiftKey) return 'pan';
245	  if (isMmb) return 'orbit';
246	  if (isLmb && event.altKey) return 'orbit';
247	  return 'idle';
248	}
249	
250	export type WheelEventLike = {
251	  deltaY: number;
252	  metaKey?: boolean;
253	  ctrlKey?: boolean;
254	};
255	
256	/** Map a wheel event to a dolly delta (positive = zoom out). */
257	export function wheelDelta(event: WheelEventLike): number {
258	  // Trackpad pinch arrives as ctrl+wheel on most browsers.
259	  if (event.metaKey || event.ctrlKey) return event.deltaY * 0.5;
260	  return event.deltaY;
261	}
262	
263	/* Hotkey resolution for §15.3. */
264	export type CameraHotkey =
265	  | { kind: 'frame-all' }
266	  | { kind: 'frame-selection' }
267	  | { kind: 'reset' }
268	  | { kind: 'zoom-in' }
269	  | { kind: 'zoom-out' }
270	  | null;
271	
272	export interface KeyEventLike {
273	  key: string;
274	  metaKey?: boolean;
275	  ctrlKey?: boolean;
276	}
277	
278	export function classifyHotkey(event: KeyEventLike): CameraHotkey {
