    const rig = cameraRigRef.current;
    if (!rig) return;
    const snap = rig.snapshot();
    rig.applyViewpoint(
      {
        x:
          snap.target.x +
          snap.radius * Math.cos(alignment.elevation) * Math.sin(alignment.azimuth),
